// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./AgentRegistry.sol";
import "./Interfaces.sol";

/**
 * @title RiskRouter
 * @notice On-chain risk gatekeeper for AI trading agents.
 *
 *         Before any trade executes, the RiskRouter:
 *         1. Verifies the EIP-712 signature — ECDSA first, EIP-1271 fallback
 *            for contract wallets (Safe, AA wallets)
 *         2. Compares signer to the agent owner recorded in AgentRegistry
 *         3. Checks trade limits (single trade + daily loss)
 *         4. Verifies the token is in the allowed list
 *         5. Emits TradeApproved / TradeRejected for indexers
 *         6. Optionally calls the DEX router for on-chain execution
 *
 * FIX applied vs original:
 *   _updateDailyStats never incremented totalLossUsd, so the daily loss limit
 *   check (stats.totalLossUsd >= maxDailyLossUsd) could never trigger — the
 *   guard was completely dead.
 *
 *   Solution: submitTrade now passes the trade's amountUsd into _updateDailyStats.
 *   On a SELL (or any trade flagged as a loss) the full amountUsd is added to
 *   totalLossUsd. For BUY trades the exposure is also tracked because the capital
 *   is at risk. The owner can adjust the accounting model via setLossAccounting().
 *
 *   Two modes controlled by lossAccountingMode:
 *     0 = CONSERVATIVE — every approved trade counts its full amountUsd as
 *         potential loss (safest, recommended for early deployment).
 *     1 = SELL_ONLY    — only SELL-action trades accumulate toward the daily
 *         loss counter (use once you have a ReputationManager feeding back
 *         real pnl outcomes).
 */
contract RiskRouter {

    // ── Events ────────────────────────────────────────────────────────────────
    event TradeApproved(
        uint256 indexed agentId,
        address indexed wallet,
        bytes32 tradeHash,
        string  tokenPair,
        string  action,
        uint256 amountUsd
    );
    event TradeRejected(
        uint256 indexed agentId,
        bytes32 tradeHash,
        string  reason
    );
    event TradeExecuted(
        uint256 indexed agentId,
        bytes32 tradeHash,
        uint256[] amounts
    );
    event TokenAllowlistUpdated(string token, bool allowed);
    event LimitsUpdated(uint256 maxSingleTradeUsd, uint256 maxDailyLossUsd);
    event DEXRouterUpdated(address dexRouter);
    event LossAccountingModeUpdated(uint8 mode);

    // ── Structs ───────────────────────────────────────────────────────────────
    struct TradeIntent {
        uint256 agentId;
        string  tokenPair;    // e.g. "ETH/USDC"
        string  action;       // "BUY" | "SELL"
        uint256 amountUsd;    // in USD cents (e.g. 10000 = $100)
        uint256 confidence;   // 0-100
        string  reason;
        uint256 nonce;
        uint256 deadline;
        // DEX execution params (optional; zero = off-chain execution)
        address tokenIn;
        address tokenOut;
        uint256 amountIn;
        uint256 amountOutMin;
    }

    struct DailyStats {
        uint256 date;
        uint256 totalLossUsd;
        uint256 tradeCount;
    }

    // ── State ─────────────────────────────────────────────────────────────────
    AgentRegistry public agentRegistry;
    IDEXRouter    public dexRouter;
    address public owner;

    uint256 public maxSingleTradeUsd = 5_000 * 100;   // $5,000 in cents
    uint256 public maxDailyLossUsd   = 10_000 * 100;  // $10,000 in cents
    uint256 public minConfidence      = 45;

    // FIX: 0 = CONSERVATIVE (all trades), 1 = SELL_ONLY
    uint8 public lossAccountingMode = 0;

    bytes4 internal constant ERC1271_MAGIC_VALUE = 0x1626ba7e;
    bytes32 private constant SELL_HASH = keccak256(bytes("SELL"));

    mapping(string  => bool)       public allowedTokens;
    mapping(uint256 => DailyStats) public agentDailyStats;
    mapping(bytes32 => bool)       public processedTrades;
    mapping(uint256 => uint256)    public agentNonces;

    bytes32 public immutable DOMAIN_SEPARATOR;
    bytes32 public constant TRADE_TYPEHASH = keccak256(
        "TradeIntent(uint256 agentId,string tokenPair,string action,uint256 amountUsd,"
        "uint256 confidence,string reason,uint256 nonce,uint256 deadline,"
        "address tokenIn,address tokenOut,uint256 amountIn,uint256 amountOutMin)"
    );

    modifier onlyOwner() {
        require(msg.sender == owner, "RiskRouter: not owner");
        _;
    }

    constructor(address _agentRegistry) {
        owner         = msg.sender;
        agentRegistry = AgentRegistry(_agentRegistry);

        allowedTokens["ETH"]   = true;
        allowedTokens["BTC"]   = true;
        allowedTokens["MATIC"] = true;
        allowedTokens["LINK"]  = true;
        allowedTokens["UNI"]   = true;
        allowedTokens["AAVE"]  = true;
        allowedTokens["USDC"]  = true;
        allowedTokens["WETH"]  = true;

        DOMAIN_SEPARATOR = keccak256(
            abi.encode(
                keccak256("EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)"),
                keccak256(bytes("AITradingAgent")),
                keccak256(bytes("1")),
                block.chainid,
                address(this)
            )
        );
    }

    // ── Core ──────────────────────────────────────────────────────────────────

    /**
     * @notice Submit a signed trade intent for risk validation.
     * @param intent    The trade parameters.
     * @param signature Raw EIP-712 signature (65-byte ECDSA or EIP-1271 bytes).
     * @return approved  Whether the trade passed all risk checks.
     * @return tradeHash Unique hash for this trade.
     */
    function submitTrade(
        TradeIntent calldata intent,
        bytes calldata signature
    ) external returns (bool approved, bytes32 tradeHash) {
        require(block.timestamp <= intent.deadline, "RiskRouter: trade expired");
        require(
            intent.nonce == agentNonces[intent.agentId],
            "RiskRouter: invalid nonce"
        );

        tradeHash = _hashTrade(intent);
        require(!processedTrades[tradeHash], "RiskRouter: already processed");

        // ── Signer MUST be the agent owner (ECDSA + EIP-1271 fallback) ────────
        address agentOwner = _getAgentOwner(intent.agentId);
        require(
            _isValidSignature(agentOwner, tradeHash, signature),
            "RiskRouter: signer is not agent owner"
        );

        (bool passed, string memory rejectReason) = _runRiskChecks(intent);

        processedTrades[tradeHash] = true;
        agentNonces[intent.agentId]++;

        if (passed) {
            // FIX: pass amountUsd into _updateDailyStats so totalLossUsd accumulates.
            _updateDailyStats(intent.agentId, intent.amountUsd, intent.action);

            emit TradeApproved(
                intent.agentId,
                agentOwner,
                tradeHash,
                intent.tokenPair,
                intent.action,
                intent.amountUsd
            );

            // Optional on-chain DEX execution
            if (
                address(dexRouter) != address(0) &&
                intent.tokenIn  != address(0)    &&
                intent.tokenOut != address(0)    &&
                intent.amountIn > 0
            ) {
                _executeDEXSwap(intent, tradeHash, agentOwner);
            }

            return (true, tradeHash);
        } else {
            emit TradeRejected(intent.agentId, tradeHash, rejectReason);
            return (false, tradeHash);
        }
    }

    // ── Internal helpers ──────────────────────────────────────────────────────

    function _isValidSignature(
        address signer,
        bytes32 hash,
        bytes memory signature
    ) internal view returns (bool) {
        // 1. ECDSA (EOA wallets)
        if (signature.length == 65) {
            bytes32 r; bytes32 s; uint8 v;
            assembly {
                r := mload(add(signature, 32))
                s := mload(add(signature, 64))
                v := byte(0, mload(add(signature, 96)))
            }
            address recovered = ecrecover(hash, v, r, s);
            if (recovered != address(0) && recovered == signer) return true;
        }

        // 2. EIP-1271 fallback (Safe, AA, Multisig)
        if (signer.code.length > 0) {
            try IERC1271(signer).isValidSignature(hash, signature)
                returns (bytes4 result)
            {
                return result == ERC1271_MAGIC_VALUE;
            } catch {
                return false;
            }
        }
        return false;
    }

    function _getAgentOwner(uint256 agentId)
        internal view returns (address agentOwner)
    {
        (,, agentOwner,,,,) = agentRegistry.getAgent(agentId);
        require(agentOwner != address(0), "RiskRouter: agent not found");
    }

    function _runRiskChecks(TradeIntent calldata intent)
        internal view returns (bool, string memory)
    {
        if (intent.confidence < minConfidence)
            return (false, "Confidence below minimum");

        if (intent.amountUsd > maxSingleTradeUsd)
            return (false, "Exceeds single trade limit");

        string memory baseToken = _extractBaseToken(intent.tokenPair);
        if (!allowedTokens[baseToken])
            return (false, "Token not in allowlist");

        DailyStats storage stats = agentDailyStats[intent.agentId];
        uint256 today = block.timestamp / 86400;
        if (stats.date == today && stats.totalLossUsd >= maxDailyLossUsd)
            return (false, "Daily loss limit reached");

        (,,,, bool active,,) = agentRegistry.getAgent(intent.agentId);
        if (!active)
            return (false, "Agent not active");

        return (true, "");
    }

    function _executeDEXSwap(
        TradeIntent calldata intent,
        bytes32 tradeHash,
        address recipient
    ) internal {
        address[] memory path = new address[](2);
        path[0] = intent.tokenIn;
        path[1] = intent.tokenOut;

        uint256[] memory amounts = dexRouter.swapExactTokensForTokens(
            intent.amountIn,
            intent.amountOutMin,
            path,
            recipient,
            intent.deadline
        );

        emit TradeExecuted(intent.agentId, tradeHash, amounts);
    }

    /**
     * FIX: Now actually increments totalLossUsd.
     *
     * Mode 0 (CONSERVATIVE): every approved trade's full amountUsd is counted
     *   toward the daily loss ceiling — safe default for testnet / early prod.
     * Mode 1 (SELL_ONLY): only SELL trades count, so BUY trades never eat into
     *   the daily loss budget — use when you trust your downstream pnl reporting.
     *
     * @param agentId   The agent submitting the trade.
     * @param amountUsd Trade size in USD cents.
     * @param action    "BUY" or "SELL" string from the intent.
     */
    function _updateDailyStats(
        uint256 agentId,
        uint256 amountUsd,
        string calldata action
    ) internal {
        uint256 today = block.timestamp / 86400;
        DailyStats storage stats = agentDailyStats[agentId];

        if (stats.date != today) {
            stats.date         = today;
            stats.totalLossUsd = 0;
            stats.tradeCount   = 0;
        }

        stats.tradeCount++;

        // FIX: accumulate loss exposure so the daily cap actually fires.
        bool isSell = keccak256(bytes(action)) == SELL_HASH;
        if (lossAccountingMode == 0 || isSell) {
            stats.totalLossUsd += amountUsd;
        }
    }

    function _hashTrade(TradeIntent calldata intent)
        internal view returns (bytes32)
    {
        bytes32 structHash = keccak256(
            abi.encode(
                TRADE_TYPEHASH,
                intent.agentId,
                keccak256(bytes(intent.tokenPair)),
                keccak256(bytes(intent.action)),
                intent.amountUsd,
                intent.confidence,
                keccak256(bytes(intent.reason)),
                intent.nonce,
                intent.deadline,
                intent.tokenIn,
                intent.tokenOut,
                intent.amountIn,
                intent.amountOutMin
            )
        );
        return keccak256(abi.encodePacked("\x19\x01", DOMAIN_SEPARATOR, structHash));
    }

    function _extractBaseToken(string calldata pair)
        internal pure returns (string memory)
    {
        bytes memory b = bytes(pair);
        uint256 slashIdx = 0;
        for (uint256 i = 0; i < b.length; i++) {
            if (b[i] == "/") { slashIdx = i; break; }
        }
        if (slashIdx == 0) return pair;
        bytes memory base = new bytes(slashIdx);
        for (uint256 i = 0; i < slashIdx; i++) base[i] = b[i];
        return string(base);
    }

    // ── Admin ─────────────────────────────────────────────────────────────────

    function setLimits(uint256 maxSingle, uint256 maxDaily) external onlyOwner {
        maxSingleTradeUsd = maxSingle;
        maxDailyLossUsd   = maxDaily;
        emit LimitsUpdated(maxSingle, maxDaily);
    }

    function setTokenAllowed(string calldata token, bool allowed) external onlyOwner {
        allowedTokens[token] = allowed;
        emit TokenAllowlistUpdated(token, allowed);
    }

    function setMinConfidence(uint256 threshold) external onlyOwner {
        minConfidence = threshold;
    }

    function setDEXRouter(address router) external onlyOwner {
        dexRouter = IDEXRouter(router);
        emit DEXRouterUpdated(router);
    }

    /**
     * @notice Set loss accounting mode.
     * @param mode 0 = CONSERVATIVE (all trades), 1 = SELL_ONLY.
     */
    function setLossAccountingMode(uint8 mode) external onlyOwner {
        require(mode <= 1, "RiskRouter: invalid mode");
        lossAccountingMode = mode;
        emit LossAccountingModeUpdated(mode);
    }

    // ── View ──────────────────────────────────────────────────────────────────

    function getAgentNonce(uint256 agentId) external view returns (uint256) {
        return agentNonces[agentId];
    }

    function isTradeProcessed(bytes32 tradeHash) external view returns (bool) {
        return processedTrades[tradeHash];
    }

    function getAgentDailyStats(uint256 agentId)
        external view
        returns (uint256 date, uint256 totalLossUsd, uint256 tradeCount)
    {
        DailyStats storage s = agentDailyStats[agentId];
        return (s.date, s.totalLossUsd, s.tradeCount);
    }
}

contracts/ValidationRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

interface IAgentRegistry {
    function ownerOf(uint256 tokenId) external view returns (address);
}

/**
 * @title ValidationRegistry
 *
 * FIXES applied vs original:
 *
 *   FIX 1 — Timestamp in artifact hash (critical, broke all storeValidation calls):
 *     The original built the artifact hash with block.timestamp on-chain, then
 *     asked the caller to sign that hash off-chain — but the caller cannot know
 *     block.timestamp before the tx mines, so ecrecover always recovered the wrong
 *     address and the tx reverted with "invalid validator signature".
 *
 *     Solution: the caller passes an explicit `timestamp` parameter. The hash is
 *     built from that caller-supplied timestamp both here and in computeArtifactHash,
 *     so off-chain signing and on-chain verification use identical inputs.
 *     storeValidation now accepts 7 args (added `timestamp`).
 *
 *   FIX 2 — onlyTradeOwnerOrAdmin reverted on non-existent tradeId:
 *     When recordOutcome was called with an unknown tradeId the modifier read
 *     _validations[tradeId].agentId == 0, passed that to _isAgentOwner(0), which
 *     either reverted or returned an unrelated address. The "trade not found" check
 *     inside the function body never ran because the modifier already blocked it.
 *
 *     Solution: existence is now checked first inside the modifier using a
 *     dedicated internal helper _tradeExists(). The "trade not found" require
 *     inside the function body is kept as a double-guard.
 *
 *   FIX 3 — Signature scheme stays personal_sign (prefix-aware):
 *     _verifySignatureWithPrefix (prepends "\x19Ethereum Signed Message:\n32")
 *     is kept unchanged — it correctly matches MetaMask signMessage / personal_sign,
 *     which is the only signing path still universally supported.
 */
contract ValidationRegistry {

    bytes32 public immutable DOMAIN_SEPARATOR;

    bytes32 public constant VALIDATION_TYPEHASH = keccak256(
        "ValidationArtifact(uint256 agentId,string tradeId,uint256 confidence,"
        "string riskCheck,uint256 timestamp,address validator)"
    );

    bytes32 public constant OUTCOME_TYPEHASH = keccak256(
        "OutcomeArtifact(string tradeId,bool profitable,int256 pnlBps,uint256 timestamp)"
    );

    event ValidationStored(
        uint256 indexed agentId,
        string  indexed tradeId,
        uint256 confidence,
        string  riskCheck,
        uint256 timestamp,
        address indexed validator
    );
    event OutcomeRecorded(string indexed tradeId, bool profitable, int256 pnlBps);
    event ValidatorAdded(address indexed validator);
    event ValidatorRemoved(address indexed validator);

    struct Validation {
        uint256 agentId;
        string  tradeId;
        string  reason;
        uint256 confidence;
        string  riskCheck;
        uint256 timestamp;
        bool    outcomeRecorded;
        bool    profitable;
        int256  pnlBps;
        address validator;
        bytes   validatorSig;
        bytes32 artifactHash;
    }

    mapping(string  => Validation) private _validations;
    mapping(uint256 => string[])   private _agentTrades;
    mapping(address => bool)       public  authorizedValidators;

    uint256 public totalValidations;
    address public owner;
    address public authorizedCaller;
    IAgentRegistry public agentRegistry;

    modifier onlyOwner() {
        require(msg.sender == owner, "ValidationRegistry: not owner");
        _;
    }

    modifier onlyAgentOwnerOrAdmin(uint256 agentId) {
        require(
            _isAgentOwner(agentId)         ||
            msg.sender == owner            ||
            msg.sender == authorizedCaller ||
            authorizedValidators[msg.sender],
            "ValidationRegistry: not authorized"
        );
        _;
    }

    /**
     * FIX 2: Check trade existence FIRST so the "not found" error surfaces
     * before the agentId lookup. Previously a missing tradeId gave agentId=0,
     * which made the authorization check meaningless or reverted unpredictably.
     */
    modifier onlyTradeOwnerOrAdmin(string calldata tradeId) {
        require(_tradeExists(tradeId), "ValidationRegistry: trade not found");
        uint256 agentId = _validations[tradeId].agentId;
        require(
            _isAgentOwner(agentId)         ||
            msg.sender == owner            ||
            msg.sender == authorizedCaller ||
            authorizedValidators[msg.sender],
            "ValidationRegistry: not authorized"
        );
        _;
    }

    constructor(address _agentRegistry) {
        owner            = msg.sender;
        authorizedCaller = msg.sender;
        authorizedValidators[msg.sender] = true;
        agentRegistry    = IAgentRegistry(_agentRegistry);

        DOMAIN_SEPARATOR = keccak256(
            abi.encode(
                keccak256("EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)"),
                keccak256(bytes("AITradingValidation")),
                keccak256(bytes("1")),
                block.chainid,
                address(this)
            )
        );
    }

    /**
     * FIX 1: Added explicit `timestamp` parameter (7 args total).
     *
     * The caller must:
     *   1. Read the latest block timestamp from the chain (or use Date.now()/1000).
     *   2. Call computeArtifactHash(agentId, tradeId, confidence, riskCheck, timestamp, validator)
     *      to get the exact bytes32 the contract will verify.
     *   3. Sign that hash with personal_sign / signMessage (prefix-aware).
     *   4. Submit here passing the same `timestamp` value used in step 2.
     *
     * The contract rebuilds the artifact hash from the supplied timestamp and
     * verifies the signature against it — both sides use the same timestamp so
     * ecrecover now recovers the correct address.
     */
    function storeValidation(
        uint256 agentId,
        string calldata tradeId,
        string calldata reason,
        uint256 confidence,
        string calldata riskCheck,
        uint256 timestamp,        // FIX 1: caller-supplied timestamp
        bytes calldata validatorSig
    ) external onlyAgentOwnerOrAdmin(agentId) {
        require(bytes(tradeId).length > 0,
            "ValidationRegistry: tradeId required");
        require(!_tradeExists(tradeId),
            "ValidationRegistry: tradeId already stored");
        require(confidence <= 100,
            "ValidationRegistry: invalid confidence");
        // Sanity: timestamp must be within ±10 minutes of current block time
        // to prevent stale or future-dated artifacts.
        require(
            timestamp >= block.timestamp - 600 && timestamp <= block.timestamp + 60,
            "ValidationRegistry: timestamp out of range"
        );

        bytes32 artifactHash = _buildArtifactHash(
            agentId, tradeId, confidence, riskCheck, timestamp, msg.sender
        );

        require(
            _verifySignatureWithPrefix(msg.sender, artifactHash, validatorSig),
            "ValidationRegistry: invalid validator signature"
        );

        _validations[tradeId] = Validation({
            agentId:         agentId,
            tradeId:         tradeId,
            reason:          _truncate(reason, 256),
            confidence:      confidence,
            riskCheck:       riskCheck,
            timestamp:       timestamp,
            outcomeRecorded: false,
            profitable:      false,
            pnlBps:          0,
            validator:       msg.sender,
            validatorSig:    validatorSig,
            artifactHash:    artifactHash
        });

        _agentTrades[agentId].push(tradeId);
        totalValidations++;

        emit ValidationStored(agentId, tradeId, confidence, riskCheck, timestamp, msg.sender);
    }

    function recordOutcome(
        string calldata tradeId,
        bool profitable,
        int256 pnlBps
    ) external onlyTradeOwnerOrAdmin(tradeId) {
        Validation storage v = _validations[tradeId];
        // Double-guard: modifier already checked existence, but kept for clarity.
        require(bytes(v.tradeId).length > 0, "ValidationRegistry: trade not found");
        require(!v.outcomeRecorded,           "ValidationRegistry: already recorded");
        v.outcomeRecorded = true;
        v.profitable      = profitable;
        v.pnlBps          = pnlBps;
        emit OutcomeRecorded(tradeId, profitable, pnlBps);
    }

    function getValidation(string calldata tradeId)
        external view
        returns (
            uint256 agentId, string memory reason, uint256 confidence,
            string memory riskCheck, uint256 timestamp,
            bool outcomeRecorded, bool profitable, int256 pnlBps
        )
    {
        Validation storage v = _validations[tradeId];
        return (v.agentId, v.reason, v.confidence, v.riskCheck,
                v.timestamp, v.outcomeRecorded, v.profitable, v.pnlBps);
    }

    function getValidationArtifact(string calldata tradeId)
        external view
        returns (address validator, bytes memory validatorSig, bytes32 artifactHash)
    {
        Validation storage v = _validations[tradeId];
        require(_tradeExists(tradeId), "ValidationRegistry: trade not found");
        return (v.validator, v.validatorSig, v.artifactHash);
    }

    function verifyValidationArtifact(string calldata tradeId)
        external view returns (bool)
    {
        Validation storage v = _validations[tradeId];
        require(_tradeExists(tradeId), "ValidationRegistry: trade not found");
        bytes32 expected = _buildArtifactHash(
            v.agentId, tradeId, v.confidence, v.riskCheck, v.timestamp, v.validator
        );
        return (
            expected == v.artifactHash &&
            _verifySignatureWithPrefix(v.validator, v.artifactHash, v.validatorSig)
        );
    }

    function computeArtifactHash(
        uint256 agentId, string calldata tradeId, uint256 confidence,
        string calldata riskCheck, uint256 timestamp, address validator
    ) external view returns (bytes32) {
        return _buildArtifactHash(agentId, tradeId, confidence, riskCheck, timestamp, validator);
    }

    function getAgentTradeIds(uint256 agentId) external view returns (string[] memory) {
        return _agentTrades[agentId];
    }

    function getAgentTradeCount(uint256 agentId) external view returns (uint256) {
        return _agentTrades[agentId].length;
    }

    function setAuthorizedCaller(address caller) external onlyOwner {
        authorizedCaller = caller;
    }

    function addValidator(address validator) external onlyOwner {
        authorizedValidators[validator] = true;
        emit ValidatorAdded(validator);
    }

    function removeValidator(address validator) external onlyOwner {
        authorizedValidators[validator] = false;
        emit ValidatorRemoved(validator);
    }

    function setAgentRegistry(address _agentRegistry) external onlyOwner {
        agentRegistry = IAgentRegistry(_agentRegistry);
    }

    // ── Internal helpers ──────────────────────────────────────────────────────

    function _tradeExists(string calldata tradeId) internal view returns (bool) {
        return bytes(_validations[tradeId].tradeId).length > 0;
    }

    function _isAgentOwner(uint256 agentId) internal view returns (bool) {
        try agentRegistry.ownerOf(agentId) returns (address agentOwner) {
            return agentOwner == msg.sender;
        } catch {
            return false;
        }
    }

    function _buildArtifactHash(
        uint256 agentId, string memory tradeId, uint256 confidence,
        string memory riskCheck, uint256 timestamp, address validator
    ) internal view returns (bytes32) {
        bytes32 structHash = keccak256(abi.encode(
            VALIDATION_TYPEHASH,
            agentId,
            keccak256(bytes(tradeId)),
            confidence,
            keccak256(bytes(riskCheck)),
            timestamp,
            validator
        ));
        return keccak256(abi.encodePacked("\x19\x01", DOMAIN_SEPARATOR, structHash));
    }

    /**
     * @notice Verify a signature produced by MetaMask personal_sign / signMessage.
     *
     * personal_sign prepends "\x19Ethereum Signed Message:\n32" to the hash
     * before signing. We apply the same prefix here so ecrecover recovers the
     * correct signer address. Equivalent to OZ ECDSA.toEthSignedMessageHash.
     */
    function _verifySignatureWithPrefix(
        address signer,
        bytes32 hash,
        bytes memory signature
    ) internal pure returns (bool) {
        if (signature.length != 65) return false;

        bytes32 prefixedHash = keccak256(
            abi.encodePacked("\x19Ethereum Signed Message:\n32", hash)
        );

        bytes32 r; bytes32 s; uint8 v;
        assembly {
            r := mload(add(signature, 32))
            s := mload(add(signature, 64))
            v := byte(0, mload(add(signature, 96)))
        }

        if (v < 27) v += 27;

        address recovered = ecrecover(prefixedHash, v, r, s);
        return (recovered != address(0) && recovered == signer);
    }

    function _truncate(string calldata str, uint256 maxLen)
        internal pure returns (string memory)
    {
        bytes calldata b = bytes(str);
        if (b.length <= maxLen) return str;
        bytes memory out = new bytes(maxLen);
        for (uint256 i = 0; i < maxLen; i++) out[i] = b[i];
        return string(out);
    }
}

